interface OAuthProviderSpec {
  provider: OAuthProvider;
  label: string;                                  // 'Gdrive' | 'OneDrive' | ... (log prefix)
  getConfig(): { clientId: string; clientSecret: string; tenantId?: string } | null;
  notConfiguredError: string;                     // exact current message — wire format
  refreshTokenUrl?(record: OAuthTokenRecord, config): string;  // gdrive/gmail: Google URL; onedrive: consumerFlow-aware; outlook: tenant URL
  buildAuthUrl(req: express.Request, config, state: string): string;  // scopes + endpoint + extras live here
  generateState(username: string, agentId: string|null, boardId: string|null, req): string;
  statusFields(token: OAuthTokenRecord|null, connected: boolean, username?: string): Record<string, unknown>; // {email}|{login}|{teamName}|{username} — preserves each wire format
  isConnected?(token): boolean;                   // default hasOAuthToken; github/slack override with their current predicates
}
export function makeRefresh(spec): (record) => Promise<string>  // the one 44-line refresh body
export function oauthProviderRoutes(spec): express.Router       // /status, /auth-url, /disconnect

